import './PDFGallery.scss';

import { Card } from ':components/Card';
import type { PDFFile } from ':components/Preview/Preview.types';
import React, { useEffect, useRef, useState } from 'react';
import type { pdfjs } from 'react-pdf';
import { Document, Page } from 'react-pdf';

export const PDFGallery = ({
	selectedIndex,
	onClick,
	value,
}: {
	selectedIndex: number;
	onClick: (index: number) => void;
	value: PDFFile;
}) => {
	const [totalPages, setTotalPages] = useState(0);
	const [loadedPages, setLoadedPages] = useState(0);
	const [allPagesLoaded, setAllPagesLoaded] = useState(false);
	const galleryRef = useRef<HTMLDivElement>(null);

	const scrollToSelected = (index: number) => {
		if (galleryRef.current) {
			const cards = galleryRef.current.querySelectorAll('.dsb_preview__gallery-pdf__frame');
			if (cards[index]) {
				const card = cards[index] as HTMLElement;
				const container = galleryRef.current;
				const cardTop = card.offsetTop;
				const cardHeight = card.offsetHeight;
				const containerHeight = container.offsetHeight;

				container.scrollTo({
					top: cardTop - containerHeight / 2 + cardHeight / 2,
					behavior: 'smooth',
				});
			}
		}
	};

	useEffect(() => {
		scrollToSelected(selectedIndex);
	}, [selectedIndex, allPagesLoaded]);

	const handleDocumentLoadSuccess = (document: pdfjs.PDFDocumentProxy) => {
		setTotalPages(document.numPages);
	};

	const handlePageLoadSuccess = () => {
		setLoadedPages(prev => {
			const newLoaded = prev + 1;
			if (newLoaded === totalPages) {
				setAllPagesLoaded(true);
			}
			return newLoaded;
		});
	};

	useEffect(() => {
		setLoadedPages(0);
		setAllPagesLoaded(false);
	}, [value.src]);

	return (
		<div className="dsb_preview__gallery-pdf" ref={galleryRef}>
			<Document
				file={value.src}
				onLoadSuccess={handleDocumentLoadSuccess}
				loading=""
				className={allPagesLoaded ? '' : 'dsb_preview__gallery-pdf__hidden'}
			>
				{Array.from({ length: totalPages }, (_, i) => (
					<div key={`page-wrapper_${i}`}>
						<Card
							border={i === selectedIndex ? 'brand' : 'default'}
							elevation="medium"
							className="dsb_preview__gallery-pdf__frame"
							onClick={() => onClick(i)}
						>
							<Page
								pageNumber={i + 1}
								loading=""
								width={44}
								className="dsb_preview__gallery-pdf__frame__page"
								renderAnnotationLayer={false}
								renderTextLayer={false}
								onLoadSuccess={handlePageLoadSuccess}
							/>
						</Card>
						<p className="dsb_preview__gallery-pdf__caption">{i + 1}</p>
					</div>
				))}
			</Document>
		</div>
	);
};
